380	     *     先 Out 再一起 In，避免新舊同時在場造成 Layout 重排跳動。
381	     *     綁定同步記錄為目標狀態（視覺在 Out 完成後才 In）。
382	     */
383	    private RebuildAll(newBounties: IBountyData[]) {
384	        const count = this.m_wantedPosterItems.length;
385	
386	        const outPromises: Promise<void>[] = [];
387	        for (let i = 0; i < count; i++) {
388	            const item = this.m_wantedPosterItems[i];
389	            if (item && item.node.active) {
390	                outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
391	            }
392	            // 同步記錄目標綁定（前 newBounties.length 個為新資料，其餘清空）
393	            this.m_currentBounty[i] = i < newBounties.length ? newBounties[i] : null;
394	        }
395	
396	        const enterAll = () => {
397	            for (let i = 0; i < newBounties.length; i++) {
398	                const item = this.m_wantedPosterItems[i];
399	                if (!item) continue;
400	                // 先 active 再 setSkin：inactive 狀態下 setSkin 不會重建已渲染骨架的 render data（殘留舊 skin）
401	                item.node.active = true;
402	                item.SetWantedPosterData(newBounties[i]);
403	                item.PlayIn();
404	            }
405	        };
406	
407	        if (outPromises.length > 0) Promise.all(outPromises).then(enterAll);
408	        else enterAll();
409	    }
